<?php declare(strict_types=1); ?>
<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Story Switchyard</title>
<style>
:root{--ink:#22211d;--paper:#f1e8cf;--red:#c6382e;--blue:#176c78;--gold:#e3a92f;--rail:#34332f;--cream:#fff9e9}
*{box-sizing:border-box}body{margin:0;color:var(--ink);font-family:"Courier New",monospace;background:#d9cfb4;background-image:radial-gradient(#77745f33 1px,transparent 1px);background-size:7px 7px;min-height:100vh}
.wrap{max-width:1050px;margin:auto;padding:20px 18px 70px}.mast{position:relative;background:var(--paper);border:3px solid var(--ink);box-shadow:8px 8px 0 var(--ink);padding:28px clamp(18px,5vw,52px);overflow:hidden}.mast:after{content:"STORIES DEPART DAILY";position:absolute;right:-45px;top:25px;transform:rotate(10deg);border:2px solid var(--red);color:var(--red);padding:7px 48px;font-weight:bold}.eyebrow{color:var(--red);font-weight:bold;letter-spacing:.18em;font-size:.72rem}h1{font:800 clamp(2.8rem,9vw,6.7rem)/.78 Georgia,serif;letter-spacing:-.06em;margin:18px 0 22px;max-width:730px}.intro{max-width:620px;line-height:1.65;font-size:.9rem}.board{margin-top:28px;display:grid;grid-template-columns:1fr 300px;gap:22px}.panel{background:var(--cream);border:3px solid var(--ink);box-shadow:6px 6px 0 var(--ink);padding:20px}.label{font-size:.7rem;letter-spacing:.12em;font-weight:bold;color:var(--blue);text-transform:uppercase}.route{position:relative;margin-top:18px;padding-left:26px}.route:before{content:"";position:absolute;left:8px;top:10px;bottom:12px;width:5px;background:repeating-linear-gradient(to bottom,var(--rail) 0 12px,transparent 12px 18px)}.stop{position:relative;margin-bottom:14px}.stop:before{content:"";position:absolute;left:-24px;top:18px;width:13px;height:13px;border-radius:50%;background:var(--gold);border:3px solid var(--ink)}.ticket{border:2px solid var(--ink);background:#fffdf4;padding:12px 13px;transform:rotate(var(--tilt));transition:.2s}.ticket:focus-within{transform:rotate(0) scale(1.015);box-shadow:4px 4px 0 var(--gold)}.ticket b{font:600 1.08rem Georgia,serif}.ticket small{display:block;color:#6e695e;margin:3px 0 8px}.ticket input{width:100%;border:0;border-bottom:2px dashed #a6a08d;background:transparent;padding:7px 2px;font:500 .84rem "Courier New";outline:none}.controls{display:grid;gap:15px}.gauge{border:2px solid var(--ink);padding:14px;background:var(--paper)}input[type=range]{width:100%;accent-color:var(--red)}button{appearance:none;border:2px solid var(--ink);padding:13px 14px;background:var(--gold);font:700 .78rem "Courier New";text-transform:uppercase;cursor:pointer;box-shadow:3px 3px 0 var(--ink);transition:.12s}button:hover{transform:translate(-1px,-1px);box-shadow:5px 5px 0 var(--ink)}button:active{transform:translate(2px,2px);box-shadow:1px 1px 0}.blue{background:var(--blue);color:white}.surprise{min-height:107px;border:2px dashed var(--red);padding:14px;line-height:1.5;color:#5e2a25;background:#fff5de}.script{margin-top:22px;display:none;background:#262621;color:#f7edcf;border:3px solid #111;padding:clamp(20px,5vw,45px);box-shadow:8px 8px 0 var(--red)}.script.show{display:block;animation:arrival .5s both}.script h2{font:800 clamp(2rem,5vw,3.7rem)/1 Georgia;color:var(--gold);margin:5px 0 20px}.script p{line-height:1.8;max-width:780px}.script .cue{color:#90d0ce;font-size:.78rem;text-transform:uppercase}.source{text-align:center;margin-top:40px;font-size:.74rem}.source a{color:var(--red);font-weight:bold}@keyframes arrival{from{transform:translateY(20px);opacity:0}}@media(max-width:760px){.board{grid-template-columns:1fr}.mast:after{display:none}.controls{grid-template-columns:1fr 1fr}.surprise,.gauge{grid-column:1/-1}}@media(max-width:470px){.controls{grid-template-columns:1fr}.surprise,.gauge{grid-column:auto}h1{font-size:3.25rem}}
</style>
</head>
<body><main class="wrap">
<header class="mast"><div class="eyebrow">PLATFORM 04 · NARRATIVE DIVISION</div><h1>Story<br>Switchyard</h1><p class="intro">Every good tale is a train: somebody wants somewhere, the line gets blocked, and the journey changes them. Fill five cars, pull a surprise lever, then conduct it aloud.</p></header>
<section class="board">
<div class="panel"><div class="label">Build your five-stop line</div><div class="route">
<?php $stops=[['The passenger','Who is this about?','A shy inventor named Milo'],['The destination','What do they want?','to win the midnight road rally'],['The obstruction','What stands in the way?','the map has been cut into puzzle pieces'],['The choice','What hard thing must they decide?','trust the rival driving beside them'],['The arrival','How are they different at the end?','brave enough to ask for help']]; foreach($stops as $i=>$s): ?>
<div class="stop"><div class="ticket" style="--tilt:<?= $i%2?'-.5deg':'.5deg' ?>"><b><?= htmlspecialchars($s[0]) ?></b><small><?= htmlspecialchars($s[1]) ?></small><input id="s<?= $i ?>" value="<?= htmlspecialchars($s[2]) ?>" aria-label="<?= htmlspecialchars($s[0]) ?>"></div></div>
<?php endforeach; ?></div></div>
<aside class="panel controls"><div><div class="label">Signal box</div><p style="font-size:.78rem;line-height:1.6">Stories need pressure, specificity, and one honest choice. The machinery is simple. The telling is yours.</p></div>
<div class="gauge"><label for="tension" class="label">Tension: <span id="tv">6</span>/10</label><input id="tension" type="range" min="1" max="10" value="6"></div>
<button id="draw">Pull surprise lever</button><div class="surprise" id="surprise"><b>UNSCHEDULED EVENT</b><br>Pull the lever when the route feels too tidy.</div>
<button class="blue" id="conduct">Conduct the story →</button><button id="randomize">Quick-start a new route</button></aside>
</section>
<section class="script" id="script"><div class="cue">Conductor's performance card</div><h2 id="scriptTitle">All aboard.</h2><div id="scriptBody"></div><button id="again">Revise the route</button></section>
<p class="source">Built after reading <a href="https://jona.ca/2011/04/how-to-tell-story.html" target="_blank" rel="noopener">Jon’s “How To Tell A Story”</a>.</p>
</main><script>
const surprises=["A friend arrives with exactly the wrong advice.","The safest route closes without warning.","An object from the opening suddenly matters.","The rival tells an uncomfortable truth.","They get what they wanted — much too early.","A tiny act of kindness costs them dearly.","The clock jumps forward ten minutes.","The apparent villain asks for help."];
const sets=[["Nathan, keeper of a suspiciously fast red car","reach the abandoned observatory before sunrise","KITT's scanner detects a bridge that is not on any map","follow the safe road or the impossible glowing one","he learns courage can sound like asking his dad to come too"],["a young knight who cannot stop sneezing","return a borrowed sword before supper","a dragon has built a blanket fort across the only pass","protect his reputation or admit why the sword is chipped","he discovers honesty is more knightly than looking perfect"],["a plumber carrying one last green mushroom","rescue the library floating above the Mushroom Kingdom","every book rearranges the world when opened","close the dangerous story or read one page further","he comes home with questions instead of trophies"]];
let eventText="";const $=x=>document.getElementById(x);$('tension').oninput=e=>$('tv').textContent=e.target.value;$('draw').onclick=()=>{eventText=surprises[Math.floor(Math.random()*surprises.length)];$('surprise').innerHTML='<b>UNSCHEDULED EVENT</b><br>'+eventText};$('randomize').onclick=()=>{const s=sets[Math.floor(Math.random()*sets.length)];s.forEach((v,i)=>$('s'+i).value=v);$('draw').click()};$('conduct').onclick=()=>{const v=[0,1,2,3,4].map(i=>$('s'+i).value.trim()||'something mysterious');const t=+$('tension').value;const weather=t>7?'with no room left for mistakes':t>4?'as the pressure quietly builds':'on a surprisingly gentle afternoon';$('scriptTitle').textContent='The line is clear.';$('scriptBody').innerHTML=`<p><span class="cue">Open close to the action</span><br>This is the story of <b>${v[0]}</b>, who wants <b>${v[1]}</b>. Begin ${weather}. Show us one small detail that makes the world real.</p><p><span class="cue">Switch the track</span><br>But <b>${v[2]}</b>. ${eventText||'Then the plan stops working in a way nobody expected.'} Slow down here. Let us feel what might be lost.</p><p><span class="cue">The heart of it</span><br>At the crucial moment, our passenger must <b>${v[3]}</b>. Do not explain the choice. Show the hand on the lever. Let us hear the silence before it moves.</p><p><span class="cue">Arrive somewhere new</span><br>The adventure ends, but not where it began: <b>${v[4]}</b>. Echo one detail from your opening, changed now. Then stop. Trust the audience.</p>`;$('script').classList.add('show');$('script').scrollIntoView({behavior:'smooth'})};$('again').onclick=()=>{window.scrollTo({top:document.querySelector('.board').offsetTop-20,behavior:'smooth'});setTimeout(()=>$('script').classList.remove('show'),400)};
</script></body></html>
